            "body": {
                "text": "Check out our latest offers!"
            },
            "action": {
                "cards": [
                    {
                        "card_index": 0,
                        "type": "cta_url",
                        "header": {
                            "type": "image",
                            "image": {
                                "link": "https://picsum.photos/200/300"
                            }
